sql:
SELECT AVG(years_of_study) AS average_years_required
FROM asl_requirements
WHERE admission_requirement = 1;

external_knowledge:
; The query uses a recursive approach to find students with a specific major and then expands to include students with shared majors. 
; ASL stands for American Sign Language; 
; The years of study required and admission and graduation requirements refer to the institution's ASL requirements.

sql:
SELECT institution_id, COUNT(course_id) AS course_count
FROM language_courses
GROUP BY institution_id;

SELECT COUNT(*) 
FROM asl_requirements 
WHERE graduation_requirement = 1;

SELECT DISTINCT type
FROM institutions
ORDER BY type;

SELECT COUNT(DISTINCT institution_id) AS institution_count
FROM asl_requirements
WHERE admission_requirement = 1 OR graduation_requirement = 1;

SELECT institution_name 
   FROM institutions 
   WHERE institution_id NOT IN (SELECT institution_id FROM asl_requirements);
